**`app/api/sites/[id]/runs/[runId]/screenshot/[fileName]/route.ts`:**

```ts
import fs from "node:fs";
import path from "node:path";
import { NextResponse } from "next/server";

export async function GET(
  _: Request,
  { params }: { params: { id: string; runId: string; fileName: string } }
) {
  if (
    !/^[\w-]+$/.test(params.id) ||
    !/^[\w-]+$/.test(params.runId) ||
    !/^[\w.-]+\.png$/.test(params.fileName)
  ) {
    return new NextResponse("Bad path", { status: 400 });
  }
  const target = path.join(
    process.cwd(), "data", "sites", params.id, "runs", params.runId, params.fileName
  );
  if (!fs.existsSync(target)) return new NextResponse("Not found", { status: 404 });
  const buf = fs.readFileSync(target);
  return new NextResponse(buf, {
    status: 200,
    headers: { "Content-Type": "image/png", "Cache-Control": "no-store" },
  });
}
```

